sql:
SELECT a.title 
FROM algorithms a 
WHERE a.algo_id = 1;

SELECT algo_id, COUNT(*) AS parameter_count
FROM algorithm_parameters
GROUP BY algo_id;

SELECT algo_id, backtest_date, result
FROM algorithm_backtest_results
WHERE result != 'success';

SELECT COUNT(DISTINCT param_value)
FROM algorithm_parameters
WHERE algo_id = 1;

external_knowledge:
- "Complete profiles" implies a comprehensive set of information for each algorithm; 
- "Top 10" refers to the first 10 results after sorting alphabetically by title; 
- "Active algorithms" means algorithms with a status of 'active'; 
- "Performance metrics" include accumulative gain, trading gain, number of trades, risk level, maximum drawdown, and Sortino ratio; 
- "Holdings" include the number of holdings, rank, holding value, and holding date; 
- "User interaction details" include user ID, interaction date, interaction type, and interaction details.

sql:
SELECT code
FROM algorithms
WHERE status = 'active';

SELECT DISTINCT a.algo_id, a.code, a.title, a.stance, a.totalsum, a.description, a.created_date, a.updated_date, a.status
FROM algorithms a
INNER JOIN holdings h ON a.algo_id = h.algo_id;
